     1→/**
     2→ * WikiLinkTransformPlugin
     3→ *
     4→ * Lexical plugin that:
     5→ * 1. Detects [[Note Title]] patterns in text
     6→ * 2. Transforms them into WikiLinkNode instances
     7→ * 3. Determines if links are broken (note doesn't exist)
     8→ * 4. Updates link states when notes are created/deleted
     9→ * 5. Handles clicks on broken links to create notes
    10→ */
    11→
    12→import { useEffect, useState } from 'react';
    13→import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
    14→import {
    15→  $getRoot,
    16→  TextNode,
    17→  COMMAND_PRIORITY_LOW,
    18→  CLICK_COMMAND,
    19→  type LexicalNode,
    20→} from 'lexical';
    21→import type { Note } from '../../types/notes';
    22→import { WikiLinkNode, $createWikiLinkNode, $isWikiLinkNode, isLinkBroken } from './WikiLinkNode';
    23→import { ConfirmDialog } from '../ConfirmDialog';
    24→import { useNotesStore } from '../../stores/useNotesStore';
    25→import { useNavigate } from 'react-router-dom';
    26→import { parseBlockReference } from '../../utils/blockReferences';
