     1→/**
     2→ * Block References Utility
     3→ *
     4→ * Utilities for working with block-level references in notes:
     5→ * - Parse block references ([[Title#block-id]])
     6→ * - Generate block IDs from headings
     7→ * - Extract manual block IDs (^block-id)
     8→ * - Find blocks in note content
     9→ */
    10→
    11→import type { BlockReference } from '../types/notes';
    12→
    13→/**
    14→ * Slugify text to create a valid block ID
    15→ *
    16→ * Rules:
    17→ * - Lowercase
    18→ * - Replace spaces with hyphens
    19→ * - Remove special characters (except hyphens)
    20→ * - Collapse multiple hyphens
    21→ * - Trim leading/trailing hyphens
    22→ *
    23→ * @example
    24→ * slugify('Getting Started') // 'getting-started'
    25→ * slugify('API & Configuration') // 'api-configuration'
    26→ */
    27→export function slugify(text: string): string {
    28→  return text
    29→    .toLowerCase()
    30→    .trim()
    31→    .replace(/[^\w\s-]/g, '') // Remove special chars except hyphens and spaces
    32→    .replace(/\s+/g, '-') // Replace spaces with hyphens
    33→    .replace(/-+/g, '-') // Collapse multiple hyphens
    34→    .replace(/^-+|-+$/g, ''); // Trim hyphens from start/end
    35→}
    36→
    37→/**
    38→ * Parse a block reference from a wiki link title
    39→ *
    40→ * Splits [[Title#block-id]] into noteTitle and blockId
    41→ * If no # present, returns just noteTitle with undefined blockId
    42→ *
    43→ * @example
    44→ * parseBlockReference('My Note#getting-started')
    45→ * // { noteTitle: 'My Note', blockId: 'getting-started' }
    46→ *
    47→ * parseBlockReference('My Note')
    48→ * // { noteTitle: 'My Note', blockId: undefined }
    49→ */
    50→export function parseBlockReference(linkTitle: string): BlockReference {
    51→  const hashIndex = linkTitle.indexOf('#');
    52→
    53→  if (hashIndex === -1) {
    54→    return {
    55→      noteTitle: linkTitle.trim(),
    56→      blockId: undefined,
    57→    };
    58→  }
    59→
    60→  return {
    61→    noteTitle: linkTitle.slice(0, hashIndex).trim(),
    62→    blockId: linkTitle.slice(hashIndex + 1).trim(),
    63→  };
    64→}
    65→
    66→/**
    67→ * Extract manual block ID from text (^block-id syntax)
    68→ *
    69→ * Looks for ^block-id at the end of a paragraph or list item
    70→ * Block ID must be alphanumeric with hyphens/underscores
    71→ *
    72→ * @example
    73→ * extractBlockId('This is important. ^key-point')
    74→ * // 'key-point'
    75→ *
    76→ * extractBlockId('No block ID here')
    77→ * // null
    78→ */
    79→export function extractBlockId(text: string): string | null {
    80→  // Match ^block-id at end of line (word chars, hyphens, underscores only)
    81→  const match = text.match(/\^([\w-]+)\s*$/);
    82→  return match ? match[1] : null;
    83→}
    84→
    85→/**
    86→ * Remove manual block ID marker from text
    87→ *
    88→ * @example
    89→ * removeBlockIdMarker('This is text. ^block-id')
    90→ * // 'This is text.'
    91→ */
    92→export function removeBlockIdMarker(text: string): string {
    93→  return text.replace(/\s*\^[\w-]+\s*$/, '').trim();
    94→}
    95→
    96→/**
    97→ * Find a block in note content by block ID
    98→ *
    99→ * Searches for:
   100→ * 1. Manual block IDs (^block-id)
   101→ * 2. Heading slugs (#heading-text → heading-text)
   102→ *
   103→ * Returns block content and surrounding context (1 line before/after)
   104→ *
   105→ * @param content - Plain text content of note
   106→ * @param blockId - Block ID to find
   107→ * @returns Block content + context, or null if not found
   108→ */
   109→export function findBlockInContent(
   110→  content: string,
   111→  blockId: string
   112→): { content: string; context: string } | null {
   113→  if (!content || !blockId) return null;
   114→
   115→  const lines = content.split('\n');
   116→  const blockIdLower = blockId.toLowerCase();
   117→
   118→  // Search for manual block ID (^block-id)
   119→  for (let i = 0; i < lines.length; i++) {
   120→    const line = lines[i];
   121→    const manualId = extractBlockId(line);
   122→
   123→    if (manualId && manualId.toLowerCase() === blockIdLower) {
   124→      // Found manual block ID
   125→      const blockContent = removeBlockIdMarker(line);
   126→      const context = getContext(lines, i);
   127→      return { content: blockContent, context };
   128→    }
   129→  }
   130→
   131→  // Search for heading slug
   132→  for (let i = 0; i < lines.length; i++) {
   133→    const line = lines[i];
   134→
   135→    // Check if line is a heading (starts with #)
   136→    if (line.trim().startsWith('#')) {
   137→      // Extract heading text (remove # symbols)
   138→      const headingText = line.replace(/^#+\s*/, '').trim();
   139→      const headingSlug = slugify(headingText);
   140→
   141→      if (headingSlug === blockIdLower) {
   142→        // Found heading with matching slug
   143→        const context = getContext(lines, i);
   144→        return { content: headingText, context };
   145→      }
   146→    }
   147→  }
   148→
   149→  return null;
   150→}
   151→
   152→/**
   153→ * Get context lines around a target line
   154→ *
   155→ * Returns 1 line before and 1 line after (if available)
   156→ */
   157→function getContext(lines: string[], targetIndex: number): string {
   158→  const contextLines: string[] = [];
   159→
   160→  // Add previous line
   161→  if (targetIndex > 0) {
   162→    contextLines.push(lines[targetIndex - 1]);
   163→  }
   164→
   165→  // Add target line
   166→  contextLines.push(lines[targetIndex]);
   167→
   168→  // Add next line
   169→  if (targetIndex < lines.length - 1) {
   170→    contextLines.push(lines[targetIndex + 1]);
   171→  }
   172→
   173→  return contextLines.join('\n');
   174→}
   175→
   176→/**
   177→ * Generate block IDs for all headings in content
   178→ *
   179→ * Returns a map of heading line index → block ID
   180→ *
   181→ * @param content - Plain text content
   182→ * @returns Map of line index to block ID
   183→ */
   184→export function generateBlockIds(content: string): Map<number, string> {
   185→  const blockIds = new Map<number, string>();
   186→
   187→  if (!content) return blockIds;
   188→
   189→  const lines = content.split('\n');
   190→
   191→  for (let i = 0; i < lines.length; i++) {
   192→    const line = lines[i];
   193→
   194→    // Check if line is a heading
   195→    if (line.trim().startsWith('#')) {
   196→      const headingText = line.replace(/^#+\s*/, '').trim();
   197→      const blockId = slugify(headingText);
   198→
   199→      if (blockId) {
   200→        blockIds.set(i, blockId);
   201→      }
   202→    }
   203→  }
   204→
   205→  return blockIds;
   206→}
   207→
   208→/**
   209→ * Extract all block references from content
   210→ *
   211→ * Finds all [[Title#block]] patterns and returns array of BlockReference objects
   212→ *
   213→ * @param content - Plain text or Lexical JSON content
   214→ * @returns Array of block references
   215→ */
   216→export function extractBlockReferences(content: string): BlockReference[] {
   217→  if (!content) return [];
   218→
   219→  const blockRefs: BlockReference[] = [];
   220→  const wikiLinkPattern = /\[\[([^\]]+)\]\]/g;
   221→  let match;
   222→
   223→  while ((match = wikiLinkPattern.exec(content)) !== null) {
   224→    const linkTitle = match[1].trim();
   225→    const blockRef = parseBlockReference(linkTitle);
   226→
   227→    // Only include if it has a block ID
   228→    if (blockRef.blockId) {
   229→      blockRefs.push(blockRef);
   230→    }
   231→  }
   232→
   233→  return blockRefs;
   234→}
   235→
   236→/**
   237→ * Create a block reference string
   238→ *
   239→ * @example
   240→ * createBlockReference('My Note', 'section-1')
   241→ * // '[[My Note#section-1]]'
   242→ */
   243→export function createBlockReference(noteTitle: string, blockId: string): string {
   244→  return `[[${noteTitle}#${blockId}]]`;
   245→}
   246→
   247→/**
   248→ * Check if a link title contains a block reference
   249→ */
   250→export function hasBlockReference(linkTitle: string): boolean {
   251→  return linkTitle.includes('#');
   252→}
   253→
   254→/**
   255→ * Validate block ID format
   256→ *
   257→ * Block IDs must:
   258→ * - Be non-empty
   259→ * - Contain only alphanumeric chars, hyphens, underscores
   260→ * - Not start or end with hyphen
   261→ */
   262→export function isValidBlockId(blockId: string): boolean {
   263→  if (!blockId) return false;
   264→
   265→  // Must match: alphanumeric, hyphens, underscores
   266→  // Cannot start/end with hyphen
   267→  return /^[a-zA-Z0-9_][\w-]*[a-zA-Z0-9_]$/.test(blockId) || /^[a-zA-Z0-9_]$/.test(blockId);
   268→}
