     1→/**
     2→ * NotePreviewPopover Component
     3→ *
     4→ * Displays note preview on hover over wiki links
     5→ * Shows title, content preview, tags, and last modified date
     6→ */
     7→
     8→import { useEffect, useRef, useState } from 'react';
     9→import { Calendar, Tag } from 'lucide-react';
    10→import type { NotePreview } from '../types/notes';
    11→import { formatDistanceToNow } from 'date-fns';
    12→
    13→interface NotePreviewPopoverProps {
    14→  preview: NotePreview | null;
    15→  position: { top: number; left: number } | null;
    16→  isLoading?: boolean;
    17→  onMouseEnter?: () => void;
    18→  onMouseLeave?: () => void;
    19→}
    20→
    21→export function NotePreviewPopover({
    22→  preview,
    23→  position,
    24→  isLoading = false,
    25→  onMouseEnter,
    26→  onMouseLeave,
    27→}: NotePreviewPopoverProps) {
    28→  const popoverRef = useRef<HTMLDivElement>(null);
    29→  const [adjustedPosition, setAdjustedPosition] = useState(position);
    30→
    31→  // Adjust position to prevent going off-screen
    32→  useEffect(() => {
    33→    if (!position || !popoverRef.current) {
    34→      setAdjustedPosition(position);
    35→      return;
    36→    }
    37→
    38→    const popover = popoverRef.current;
    39→    const rect = popover.getBoundingClientRect();
    40→    const viewport = {
    41→      width: window.innerWidth,
    42→      height: window.innerHeight,
    43→    };
    44→
    45→    let { top, left } = position;
    46→
    47→    // Adjust horizontal position if going off right edge
    48→    if (left + rect.width > viewport.width - 20) {
    49→      left = viewport.width - rect.width - 20;
    50→    }
    51→
    52→    // Adjust horizontal position if going off left edge
    53→    if (left < 20) {
    54→      left = 20;
    55→    }
    56→
    57→    // Adjust vertical position if going off bottom edge
    58→    if (top + rect.height > viewport.height - 20) {
    59→      top = viewport.height - rect.height - 20;
    60→    }
    61→
    62→    // Adjust vertical position if going off top edge
    63→    if (top < 20) {
    64→      top = 20;
    65→    }
    66→
    67→    setAdjustedPosition({ top, left });
    68→  }, [position, preview]);
    69→
    70→  if (!position || (!preview && !isLoading)) return null;
    71→
    72→  return (
    73→    <div
    74→      ref={popoverRef}
    75→      className="fixed z-50 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg shadow-lg pointer-events-auto"
    76→      style={{
    77→        top: adjustedPosition?.top ?? position.top,
    78→        left: adjustedPosition?.left ?? position.left,
